import androidx.appcompat.app.AppCompatActivity;
import androidx.core.content.FileProvider;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.provider.MediaStore;
import android.util.Log;

public class ShareActivity extends AppCompatActivity {
    private static final String TAG = "ShareActivity";
    private static final int REQUEST_IMAGE = 1;
    private Uri imageUri;
    private String textContent;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_share);

        handleIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleIntent(intent);
    }

    private void handleIntent(Intent intent) {
        if (intent.hasExtra(Intent.EXTRA_TEXT)) {
            textContent = intent.getStringExtra(Intent.EXTRA_TEXT);
        } else if (intent.hasExtra(Intent.EXTRA_STREAM)) {
            handleImage((Uri) intent.getParcelableExtra(Intent.EXTRA_STREAM));
        }
    }

    private void handleImage(Uri uri) {
        imageUri = uri;
        // Here you can perform operations with the received image or show it to the user
    }

    public static Intent createChooserIntent() {
        Intent intent = new Intent(Intent.ACTION_SEND);
        intent.addCategory(Intent.CATEGORY_OPENABLE);
        intent.setType("image/*");

        Intent textIntent = new Intent(Intent.ACTION_SEND);
        textIntent.setType("text/plain");

        Intent chooserIntent = Intent.createChooser(intent, "Share image or text");
        chooserIntent.putExtra(Intent.EXTRA_INITIAL_INTENTS, new Intent[]{textIntent});
        return chooserIntent;
    }
}